sharedInterfaces.definition:
export interface Frontier {
  readonly id: string;
  readonly theme: string;                    // human-readable label
  readonly themeKeys: readonly string[];     // normalized n-gram keys for saturation overlap
  readonly candidates: readonly DivergentCandidate[];
  readonly signalStrength: number;           // [0,1]
  readonly novelty: number;                  // [0,1] = (1-mem0Score)*(1-saturationPenalty)
  readonly score: number;                    // signalStrength * novelty
  readonly seedText: string;                 // synthetic enrichedSeed for the depth game
}

export interface BroadCorpus {
  readonly trends: TrendData;                   // from src/pipelines/ideas/types.ts
  readonly pains: ClusteredPains;               // from src/pipelines/ideas/types.ts
  readonly capabilities: CapabilityScan;        // from src/pipelines/ideas/types.ts
  readonly deepSearchContext?: string;
}

export interface DiscoveryResult {
  readonly candidates: readonly DivergentCandidate[];  // flat broad pool
  readonly frontiers: readonly Frontier[];              // ranked desc by score
}

export interface FrontierScoringContext {
  readonly userId: string;
  readonly saturatedThemeKeys: readonly string[];
  readonly deepNovelty?: boolean;
  readonly signal?: AbortSignal;
}

export interface DiscoverFrontiersOptions {
  readonly broadPoolSize?: number;
  readonly maxDeepFrontiers?: number;
  readonly userId?: string;
  readonly config?: SigeSessionConfig;
  readonly deepNovelty?: boolean;
  readonly saturatedThemeKeys?: readonly string[];
  readonly signal?: AbortSignal;
}

export type AutoTickResult = {
  readonly enqueued: boolean;
  readonly reason: 'enqueued' | 'disabled' | 'already-active' | 'too-soon' | 'error';
  readonly sessionId?: string;
};

// Added to SigeSession (types.ts:336):
//   readonly seedInput?: string;      // was: readonly seedInput: string
//   readonly origin: 'human' | 'auto';
//   readonly mode?: 'seeded' | 'autonomous';
export type SigeSessionOrigin = 'human' | 'auto';

// Branded string: raw scraped text after wrapUntrusted. Prevents passing
// unsanitized scraped text where a wrapped block is required at call sites.
type UntrustedBlock = string & { readonly __untrusted: unique symbol };

export interface SigeRunSlot {
  readonly acquired: boolean;
  readonly release: () => Promise<void>;
}
